window.queryError=(e,r,t)=>new Error(`${e}\n > ${r}   ${t}`),window.$=(e,r)=>{if(!e)throw window.queryError("Attempted query without an operator!",e,r);switch(e){case"el":return document.querySelector(r);case"EL":return document.querySelectorAll(r);case"ls":return localStorage.getItem(r);case"LS":if(!r.includes(";"))throw window.queryError("Params must match pattern: key;value",e,r);const[t,o]=r.split(";",2);return void localStorage.setItem(t,o);case"ss":return sessionStorage.getItem(r);case"SS":if(!r.includes(";"))throw window.queryError("Params must match pattern: key;value",e,r);const[a,s]=r.split(";",2);return void sessionStorage.setItem(a,s);default:throw window.queryError("Attempted query with an invalid operator!",e,r)}};
